import{useEffect}from"react";import*as React from"react";import{CustomResizeObserver}from"../lib/floating/customResizeObserver";import{useStableCallback}from"./useStableCallback";function useResizeObserver(s,e){const t=useStableCallback(e);useEffect(function(){if(s&&s.current){const e=s.current,r=new CustomResizeObserver(()=>t(e));return r.observe(e),r.appendToTheDOM(),()=>r.disconnect()}},[s,t])}export{useResizeObserver};